#include<stdio.h>
int main()
{
    int j,k;
    int a[4];
    scanf("%d",&a[0]);
    for(int i=1;i<4;i++)
    {
        scanf("%d",&a[i]);
        int key=a[i];
        j=i-1;
        if(a[j]>key)
        {
            while(j>=0 && a[j]>key)
            {
                a[j+1]=a[j];
                j--;
            }
            a[j+1]=key;
        }
    }
    if(a[0]+a[3]==a[1]+a[2] || a[0]+a[1]+a[2]==a[3] )
        printf("YES");
    else
        printf("NO");



}

