fn input_split() -> Vec<u8> {
    let mut buf = String::new();
    std::io::stdin().read_line(&mut buf).unwrap();
    buf.trim()
        .split_whitespace()
        .map(|elem| elem.parse().unwrap())
        .collect()
}

fn main() {
    let mut bags = input_split();
    bags.sort_unstable_by(|a, b| b.cmp(&a));

    let mut first_friend = 0;
    let mut second_friend = 0;

    for bag in bags {
        if first_friend < second_friend {
            first_friend += bag;
        } else {
            second_friend += bag;
        }
    }

    print!(
        "{}",
        if first_friend == second_friend {
            "YES"
        } else {
            "NO"
        }
    )
}
